#!/usr/bin/env python3
"""Regenerate the quiz webpage from questions_full.json.
Usage: python3 build_quiz.py  ->  writes AWS_GenAI_Quiz.html
"""
import json
data = json.dumps(json.load(open("questions_full.json", encoding="utf-8")), ensure_ascii=False)
TEMPLATE = '<!DOCTYPE html>\n<html lang="zh-Hant">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>AWS GenAI 考試練習 (Q1–Q97)</title>\n<style>\n  * { box-sizing: border-box; }\n  :root{\n    --bg:#0f172a; --card:#1e293b; --card2:#273449; --text:#e2e8f0; --muted:#94a3b8;\n    --accent:#f59e0b; --accent2:#fbbf24; --green:#22c55e; --red:#ef4444; --blue:#38bdf8;\n    --border:#334155;\n  }\n  body{\n    margin:0; font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","PingFang TC","Microsoft JhengHei",sans-serif;\n    background:linear-gradient(160deg,#0b1224,#111c33); color:var(--text); line-height:1.6;\n    min-height:100vh; padding:24px 14px;\n  }\n  .wrap{ max-width:880px; margin:0 auto; }\n  h1{ font-size:1.5rem; margin:0 0 4px; }\n  .sub{ color:var(--muted); font-size:.9rem; margin-bottom:20px; }\n  .card{ background:var(--card); border:1px solid var(--border); border-radius:16px; padding:24px; box-shadow:0 10px 30px rgba(0,0,0,.3); }\n  .hidden{ display:none; }\n  button{ cursor:pointer; font-family:inherit; }\n  .btn{\n    background:var(--accent); color:#1a1205; border:none; padding:13px 22px; border-radius:10px;\n    font-size:1rem; font-weight:700; transition:.15s;\n  }\n  .btn:hover{ background:var(--accent2); transform:translateY(-1px); }\n  .btn.secondary{ background:transparent; color:var(--text); border:1px solid var(--border); }\n  .btn.secondary:hover{ background:var(--card2); }\n  .btn:disabled{ opacity:.4; cursor:not-allowed; transform:none; }\n  .topbar{ display:flex; justify-content:space-between; align-items:center; gap:12px; margin-bottom:14px; flex-wrap:wrap; }\n  .progress{ font-size:.85rem; color:var(--muted); }\n  .pill{ background:var(--card2); padding:4px 12px; border-radius:999px; font-size:.8rem; font-weight:600; }\n  .bar{ height:7px; background:var(--card2); border-radius:999px; overflow:hidden; margin-bottom:18px; }\n  .bar > i{ display:block; height:100%; background:linear-gradient(90deg,var(--accent),var(--accent2)); width:0; transition:width .3s; }\n  .stem{ font-size:1.06rem; margin:6px 0 18px; white-space:pre-wrap; }\n  .tag{ display:inline-block; font-size:.75rem; font-weight:700; padding:3px 10px; border-radius:8px; margin-bottom:10px; }\n  .tag.single{ background:rgba(56,189,248,.15); color:var(--blue); }\n  .tag.multi{ background:rgba(245,158,11,.15); color:var(--accent2); }\n  .tag.origin{ background:rgba(148,163,184,.18); color:#cbd5e1; margin-right:8px; }\n  .opt{\n    display:flex; gap:12px; align-items:flex-start; background:var(--card2); border:2px solid transparent;\n    border-radius:12px; padding:13px 15px; margin-bottom:10px; cursor:pointer; transition:.12s;\n  }\n  .opt:hover{ border-color:var(--border); }\n  .opt.selected{ border-color:var(--accent); background:#33405a; }\n  .opt .lab{ font-weight:800; min-width:22px; color:var(--accent2); }\n  .opt.correct{ border-color:var(--green); background:rgba(34,197,94,.13); }\n  .opt.wrong{ border-color:var(--red); background:rgba(239,68,68,.13); }\n  .opt.disabled{ cursor:default; }\n  .mark{ margin-left:auto; font-weight:800; }\n  .explain{\n    margin-top:16px; padding:15px 17px; background:rgba(56,189,248,.08); border-left:4px solid var(--blue);\n    border-radius:8px; white-space:pre-wrap; font-size:.95rem;\n  }\n  .explain b{ color:var(--accent2); }\n  .result-banner{ font-weight:800; font-size:1.05rem; margin-bottom:10px; }\n  .ok{ color:var(--green); } .no{ color:var(--red); }\n  .footer-actions{ display:flex; gap:10px; margin-top:20px; flex-wrap:wrap; }\n  .stat-grid{ display:grid; grid-template-columns:repeat(3,1fr); gap:14px; margin:20px 0; }\n  .stat{ background:var(--card2); border-radius:14px; padding:18px; text-align:center; }\n  .stat .n{ font-size:2rem; font-weight:800; }\n  .stat .l{ font-size:.8rem; color:var(--muted); }\n  .wronglist{ margin-top:10px; }\n  .wq{ border:1px solid var(--border); border-radius:12px; padding:14px; margin-bottom:12px; background:var(--card2); }\n  .wq .qn{ font-weight:700; color:var(--accent2); margin-bottom:6px; }\n  .wq .small{ font-size:.88rem; }\n  .answer-line{ font-size:.9rem; margin-top:6px; }\n  .num-input{ width:80px; padding:8px; border-radius:8px; border:1px solid var(--border); background:var(--card2); color:var(--text); font-size:1rem; }\n  label.field{ display:flex; align-items:center; gap:10px; margin:14px 0; font-size:.95rem; color:var(--muted); flex-wrap:wrap;}\n  .donut{ display:block; margin:0 auto; }\n  .zh{ display:none; margin-top:6px; color:#cbd5e1; font-size:.93rem; line-height:1.55; border-left:3px solid var(--border); padding-left:10px; white-space:pre-wrap; }\n  body.show-zh .zh{ display:block; }\n  .opt .txt .zh{ font-size:.9rem; }\n  @media(max-width:560px){ .stat-grid{ grid-template-columns:1fr; } }\n</style>\n</head>\n<body>\n<div class="wrap">\n\n  <!-- START -->\n  <div id="start" class="card">\n    <h1>🟧 AWS GenAI 考試練習</h1>\n    <div class="sub">題庫 Q1–Q97 ・ 每次隨機出題，作答後立即顯示對錯與考點，結束統計錯題</div>\n    <label class="field">\n      出題數量：\n      <input id="count" class="num-input" type="number" min="1" max="97" value="97">\n      <span>題（最多 97，會從題庫隨機抽取並打亂順序）</span>\n    </label>\n    <label class="field">\n      <input id="instant" type="checkbox" checked style="width:18px;height:18px;">\n      作答後立即顯示答案與解析\n    </label>\n    <div class="footer-actions">\n      <button class="btn" onclick="startQuiz()">開始測驗 ▶</button>\n    </div>\n  </div>\n\n  <!-- QUIZ -->\n  <div id="quiz" class="card hidden">\n    <div class="topbar">\n      <span class="progress" id="progress"></span>\n      <span class="pill" id="livescore"></span>\n    </div>\n    <div class="bar"><i id="barfill"></i></div>\n    <div id="tag"></div>\n    <div class="stem" id="stem"></div>\n    <div id="options"></div>\n    <div id="explainBox"></div>\n    <div class="footer-actions">\n      <button class="btn" id="submitBtn" onclick="submitAnswer()">送出答案</button>\n      <button class="btn hidden" id="nextBtn" onclick="nextQuestion()">下一題 →</button>\n      <button class="btn secondary" onclick="if(confirm(\'確定要結束並查看統計嗎？\')) finish()">結束並統計</button>\n      <button class="btn secondary zhBtn" onclick="toggleZh()">中文</button>\n    </div>\n  </div>\n\n  <!-- RESULT -->\n  <div id="result" class="card hidden">\n    <h1>📊 測驗結果</h1>\n    <div class="sub" id="resultSub"></div>\n    <svg class="donut" id="donut" width="160" height="160" viewBox="0 0 160 160"></svg>\n    <div class="stat-grid">\n      <div class="stat"><div class="n" id="sTotal"></div><div class="l">作答題數</div></div>\n      <div class="stat"><div class="n ok" id="sRight"></div><div class="l">答對</div></div>\n      <div class="stat"><div class="n no" id="sWrong"></div><div class="l">答錯</div></div>\n    </div>\n    <div id="wrongWrap"></div>\n    <div class="footer-actions">\n      <button class="btn" onclick="location.reload()">🔁 重新開始</button>\n      <button class="btn secondary" id="redoWrongBtn" onclick="redoWrong()">只練習錯題 ↻</button>\n      <button class="btn secondary zhBtn" onclick="toggleZh()">中文</button>\n    </div>\n  </div>\n\n</div>\n\n<script>\nconst QUESTIONS = __DATA__;\nlet pool=[], idx=0, results=[], current=null, selected=new Set(), answered=false, instant=true;\n\nfunction shuffle(a){ for(let i=a.length-1;i>0;i--){ const j=Math.floor(Math.random()*(i+1)); [a[i],a[j]]=[a[j],a[i]]; } return a; }\n\nfunction startQuiz(){\n  let n = parseInt(document.getElementById(\'count\').value)||97;\n  n = Math.max(1, Math.min(97, n));\n  instant = document.getElementById(\'instant\').checked;\n  pool = shuffle(QUESTIONS.slice()).slice(0, n);\n  idx=0; results=[];\n  document.getElementById(\'start\').classList.add(\'hidden\');\n  document.getElementById(\'result\').classList.add(\'hidden\');\n  document.getElementById(\'quiz\').classList.remove(\'hidden\');\n  renderQuestion();\n}\n\nfunction renderQuestion(){\n  current = pool[idx];\n  selected = new Set(); answered=false;\n  const multi = current.answers.length>1;\n  document.getElementById(\'progress\').textContent = `第 ${idx+1} / ${pool.length} 題`;\n  const right = results.filter(r=>r.correct).length;\n  document.getElementById(\'livescore\').textContent = `✔ ${right}\u3000✘ ${results.length-right}`;\n  document.getElementById(\'barfill\').style.width = (idx/pool.length*100)+\'%\';\n  const typeTag = multi\n    ? `<span class="tag multi">複選 — 請選 ${current.answers.length} 個</span>`\n    : `<span class="tag single">單選</span>`;\n  document.getElementById(\'tag\').innerHTML =\n    `<span class="tag origin">📄 原文件 Question #${current.num}</span>${typeTag}`;\n  document.getElementById(\'stem\').innerHTML = escapeHtml(current.stem) + (current.stem_zh ? `<div class="zh">${escapeHtml(current.stem_zh)}</div>` : \'\');\n  const ob = document.getElementById(\'options\'); ob.innerHTML=\'\';\n  Object.keys(current.options).sort().forEach(letter=>{\n    const div=document.createElement(\'div\');\n    div.className=\'opt\'; div.dataset.letter=letter;\n    const ozh = (current.options_zh && current.options_zh[letter]) ? `<div class="zh">${escapeHtml(current.options_zh[letter])}</div>` : \'\';\n    div.innerHTML=`<span class="lab">${letter}</span><span class="txt">${escapeHtml(current.options[letter])}${ozh}</span>`;\n    div.onclick=()=>toggle(letter,multi,div);\n    ob.appendChild(div);\n  });\n  document.getElementById(\'explainBox\').innerHTML=\'\';\n  document.getElementById(\'submitBtn\').classList.remove(\'hidden\');\n  document.getElementById(\'submitBtn\').disabled=true;\n  document.getElementById(\'nextBtn\').classList.add(\'hidden\');\n}\n\nfunction toggle(letter,multi,div){\n  if(answered) return;\n  if(multi){\n    if(selected.has(letter)){ selected.delete(letter); div.classList.remove(\'selected\'); }\n    else { selected.add(letter); div.classList.add(\'selected\'); }\n  } else {\n    selected.clear();\n    document.querySelectorAll(\'.opt\').forEach(o=>o.classList.remove(\'selected\'));\n    selected.add(letter); div.classList.add(\'selected\');\n  }\n  document.getElementById(\'submitBtn\').disabled = selected.size===0;\n}\n\nfunction submitAnswer(){\n  if(selected.size===0) return;\n  answered=true;\n  const correctSet = new Set(current.answers);\n  const sel = [...selected].sort();\n  const isCorrect = sel.length===correctSet.size && sel.every(s=>correctSet.has(s));\n  results.push({num:current.num, correct:isCorrect, selected:sel, correctAns:current.answers, q:current});\n\n  document.querySelectorAll(\'.opt\').forEach(o=>{\n    const L=o.dataset.letter; o.classList.add(\'disabled\'); o.onclick=null;\n    if(correctSet.has(L)){ o.classList.add(\'correct\'); o.querySelector(\'.lab\').insertAdjacentHTML(\'afterend\',\' \'); o.insertAdjacentHTML(\'beforeend\',\'<span class="mark ok">✔</span>\'); }\n    else if(selected.has(L)){ o.classList.add(\'wrong\'); o.insertAdjacentHTML(\'beforeend\',\'<span class="mark no">✘</span>\'); }\n  });\n\n  const eb=document.getElementById(\'explainBox\');\n  const banner = isCorrect ? \'<span class="ok">✅ 答對了！</span>\' : `<span class="no">❌ 答錯了</span>\u3000正確答案：<b>${current.answers.join(\', \')}</b>`;\n  let exp = current.explain ? `<div class="explain"><b>考點背法 🎯</b><br>${escapeHtml(current.explain)}</div>` : \'\';\n  eb.innerHTML = `<div class="result-banner">${banner}</div>${exp}`;\n\n  document.getElementById(\'submitBtn\').classList.add(\'hidden\');\n  document.getElementById(\'nextBtn\').classList.remove(\'hidden\');\n  const right = results.filter(r=>r.correct).length;\n  document.getElementById(\'livescore\').textContent = `✔ ${right}\u3000✘ ${results.length-right}`;\n\n  if(!instant){ /* still show because requested simple */ }\n}\n\nfunction nextQuestion(){\n  idx++;\n  if(idx>=pool.length){ finish(); return; }\n  renderQuestion();\n}\n\nfunction finish(){\n  document.getElementById(\'quiz\').classList.add(\'hidden\');\n  document.getElementById(\'result\').classList.remove(\'hidden\');\n  const total=results.length;\n  const right=results.filter(r=>r.correct).length;\n  const wrong=total-right;\n  document.getElementById(\'sTotal\').textContent=total;\n  document.getElementById(\'sRight\').textContent=right;\n  document.getElementById(\'sWrong\').textContent=wrong;\n  const pct = total? Math.round(right/total*100):0;\n  document.getElementById(\'resultSub\').textContent = `總共作答 ${total} 題，答對 ${right} 題、答錯 ${wrong} 題，正確率 ${pct}%。`;\n  drawDonut(pct);\n\n  const wrongs=results.filter(r=>!r.correct);\n  const ww=document.getElementById(\'wrongWrap\');\n  if(wrongs.length===0){\n    ww.innerHTML=\'<div class="explain ok"><b>🎉 全部答對，太強了！</b></div>\';\n    document.getElementById(\'redoWrongBtn\').style.display=\'none\';\n  } else {\n    let h=`<h1 style="font-size:1.1rem;margin-top:10px;">❌ 錯題回顧（${wrongs.length} 題）</h1><div class="wronglist">`;\n    wrongs.forEach(r=>{\n      let opts = Object.keys(r.q.options).sort().map(L=>{\n        const isC=r.correctAns.includes(L), isS=r.selected.includes(L);\n        let pre = isC?\'✔ \':(isS?\'✘ \':\'\u3000\');\n        let style = isC?\'color:var(--green);font-weight:700\':(isS?\'color:var(--red)\':\'\');\n        const ozh = (r.q.options_zh && r.q.options_zh[L]) ? `<div class="zh">${escapeHtml(r.q.options_zh[L])}</div>` : \'\';\n        return `<div class="small" style="${style}">${pre}${L}. ${escapeHtml(r.q.options[L])}${ozh}</div>`;\n      }).join(\'\');\n      h+=`<div class="wq"><div class="qn">📄 原文件 Question #${r.num}</div>\n          <div class="small">${escapeHtml(r.q.stem)}${r.q.stem_zh?`<div class="zh">${escapeHtml(r.q.stem_zh)}</div>`:\'\'}</div>\n          <div style="margin-top:8px;">${opts}</div>\n          <div class="answer-line">你的選擇：<b class="no">${r.selected.join(\', \')||\'—\'}</b>\u3000|\u3000正確答案：<b class="ok">${r.correctAns.join(\', \')}</b></div>\n          ${r.q.explain?`<div class="explain"><b>考點背法 🎯</b><br>${escapeHtml(r.q.explain)}</div>`:\'\'}\n        </div>`;\n    });\n    h+=\'</div>\';\n    ww.innerHTML=h;\n    document.getElementById(\'redoWrongBtn\').style.display=\'\';\n    window._wrongNums = wrongs.map(r=>r.num);\n  }\n}\n\nfunction redoWrong(){\n  const nums = window._wrongNums||[];\n  if(!nums.length) return;\n  pool = shuffle(QUESTIONS.filter(q=>nums.includes(q.num)));\n  idx=0; results=[];\n  document.getElementById(\'result\').classList.add(\'hidden\');\n  document.getElementById(\'quiz\').classList.remove(\'hidden\');\n  renderQuestion();\n}\n\nfunction drawDonut(pct){\n  const svg=document.getElementById(\'donut\'); const r=64, c=2*Math.PI*r, off=c*(1-pct/100);\n  const col = pct>=80?\'#22c55e\':(pct>=60?\'#f59e0b\':\'#ef4444\');\n  svg.innerHTML=`\n    <circle cx="80" cy="80" r="${r}" fill="none" stroke="#273449" stroke-width="16"/>\n    <circle cx="80" cy="80" r="${r}" fill="none" stroke="${col}" stroke-width="16"\n       stroke-dasharray="${c}" stroke-dashoffset="${off}" stroke-linecap="round"\n       transform="rotate(-90 80 80)"/>\n    <text x="80" y="80" text-anchor="middle" dominant-baseline="central"\n       fill="#e2e8f0" font-size="30" font-weight="800">${pct}%</text>`;\n}\n\nfunction escapeHtml(s){ return (s||\'\').replace(/&/g,\'&amp;\').replace(/</g,\'&lt;\').replace(/>/g,\'&gt;\'); }\n\nfunction toggleZh(){\n  const on = document.body.classList.toggle(\'show-zh\');\n  document.querySelectorAll(\'.zhBtn\').forEach(b=>b.textContent = on ? \'隱藏中文\' : \'中文\');\n}\n</script>\n</body>\n</html>'
open("AWS_GenAI_Quiz.html","w",encoding="utf-8").write(TEMPLATE.replace("__DATA__", data))
print("saved AWS_GenAI_Quiz.html")
